<div class="table-responsive"><table class="table align-middle"><thead><tr><th>Fecha</th><th>Evento</th><th>Modulo</th><th>Resultado</th><th>Descripcion</th></tr></thead><tbody><?php foreach($actividad as $evento):?><tr><td><?= date('d/m/Y H:i',strtotime((string)$evento['created_at'])) ?></td><td><?= atenea_e((string)$evento['event_type']) ?></td><td><?= atenea_e((string)$evento['module']) ?></td><td><span class="badge badge-opacity-<?= $evento['result']==='success'?'success':'danger' ?>"><?= atenea_e((string)$evento['result']) ?></span></td><td><?= atenea_e((string)$evento['description']) ?></td></tr><?php endforeach;?><?php if(!$actividad):?><tr><td colspan="5" class="text-center text-muted">Sin actividad registrada.</td></tr><?php endif;?></tbody></table></div>
